import { renderRoot } from "../../render";

let state = {
  messegData: [],
  newChange: [],
};

export let addPost = (newMessege) => {
  let newPost = {
    id: 5,
    messege: newMessege,
    like: 23,
  };
  state.messegData.push(newPost);
  renderRoot(state);
};

export let upDateChange = (newChange) => {
  state.newChange = newChange;
  console.log(state.newChange);
  console.log(state.messegData);
};

export default state;
